// Expected sheet columns:
// Name        – person's name, e.g. "John Doe"
// Date        – MM-DD, e.g. "06-15"  (recurring yearly)
// Type        – "Birth Anniversary" | "Death Anniversary" | "Other"
// InstanceID  – Botsab instance ID
// GroupID     – WhatsApp group JID, e.g. "120363XXXXXXX@g.us"
// CustomMessage – (optional) override message text

const REMINDER_DAYS = [35, 14, 7, 3, 1, 0]; // days before (0 = on the day)

const today = new Date();
today.setHours(0, 0, 0, 0);

const results = [];

for (const item of $input.all()) {
  const { Name, Date: dateStr, Type, InstanceID, GroupID, CustomMessage } = item.json;
  if (!dateStr || !GroupID || !InstanceID || !Name) continue;

  const parts = String(dateStr).split('-');
  if (parts.length < 2) continue;
  const month = parseInt(parts[0], 10) - 1; // 0-indexed
  const day   = parseInt(parts[1], 10);

  const thisYear = today.getFullYear();
  let anniversary = new Date(thisYear, month, day);
  anniversary.setHours(0, 0, 0, 0);

  // If already passed this year, use next year
  if (anniversary < today) {
    anniversary = new Date(thisYear + 1, month, day);
  }

  const daysUntil = Math.round((anniversary.getTime() - today.getTime()) / 86_400_000);

  if (!REMINDER_DAYS.includes(daysUntil)) continue;

  const typeLabel = String(Type || 'Anniversary');
  let message;
  if (CustomMessage) {
    // Support {{name}}, {{type}}, {{days}} placeholders in custom message
    message = String(CustomMessage)
      .replace('{{name}}', Name)
      .replace('{{type}}', typeLabel)
      .replace('{{days}}', String(daysUntil));
  } else if (daysUntil === 0) {
    message = `🎉 Today is ${Name}'s ${typeLabel}! Wishing them all the best.`;
  } else if (daysUntil === 1) {
    message = `🔔 Reminder: Tomorrow is ${Name}'s ${typeLabel}!`;
  } else {
    message = `🔔 Reminder: ${Name}'s ${typeLabel} is in ${daysUntil} days (${anniversary.toLocaleDateString('en-IN', { day: 'numeric', month: 'long' })}).`;
  }

  results.push({
    json: {
      instanceId: String(InstanceID),
      groupId: String(GroupID),
      message,
      name: String(Name),
      type: typeLabel,
      daysUntil,
      anniversaryDate: anniversary.toISOString().split('T')[0],
    }
  });
}

return results;
